"""Bundled brand assets, base64-embedded so they ship with both the pip package
and the PyInstaller binary without separate data files."""

import base64

# The SAI mark (the site favicon.png), used as the example/preview card logo.
SAI_MARK_PNG_B64 = ""


def sai_mark_png() -> bytes:
    return base64.b64decode(SAI_MARK_PNG_B64)